op_000144.formalized_statement:
∀ p : AtomicResidualState, ∀ R : Finset AtomicResidualState,
  (∀ q : AtomicResidualState, q ∈ R ↔ Relation.ReflTransGen AtomicResidualGraphStep p q) →
    let S0 : Set AtomicResidualState :=
      {q : AtomicResidualState | q = ([# (p.2)], p.2) ∧ q ∈ R}
    let step : Set AtomicResidualState → Set AtomicResidualState :=
      fun S =>
        S ∪ {q : AtomicResidualState | q ∈ R ∧ ∃ r : AtomicResidualState, AtomicResidualGraphStep q r ∧ r ∈ S}
    Nat.iterate step R.card S0 = {q : AtomicResidualState | q ∈ R ∧ AtomicResidualGraphAccepts q}
